block_descriptions.code:
always @(*)
case (forward_a)
		2'd1: fw_data1_s3 = alurslt_s4;
		2'd2: fw_data1_s3 = wrdata_s5;
	 default: fw_data1_s3 = data1_s3;
endcase

always @(*)
case (forward_b)
		2'd1: fw_data2_s3 = alurslt_s4;
		2'd2: fw_data2_s3 = wrdata_s5;
	 default: fw_data2_s3 = data2_s3;
endcase

always @(*) begin
	case (1'b1)
		branch_eq_s4: pcsrc <= zero_s4;
		branch_ne_s4: pcsrc <= ~(zero_s4);
		default: pcsrc <= 1'b0;
	endcase
end
// }}}

// {{{ stage 5, WB (write back)

assign wrdata_s5 = (memtoreg_s5 == 1'b1) ? rdata_s5 : alurslt_s5;

// }}}

// {{{ forwarding

// stage 3 (MEM) -> stage 2 (EX)
// stage 4 (WB) -> stage 2 (EX)

	always @(*) begin
		if (memread_s3 == 1'b1 && ((rt == rt_s3) || (rs == rt_s3)) ) begin
			stall_s1_s2 <= 1'b1;  // perform a stall
		end else
			stall_s1_s2 <= 1'b0;  // no stall
	end
	// }}}

endmodule

// vim:foldmethod=marker

		$monitor("%x, %x, %x, %x, %x, %x, %x,         %x,    %x,           %x,            %x,   %x",
				pc,				/* if_pc */
				inst,			/* if_instr */
				data1,			/* id_regrs */
				data2,			/* id_regrt */
				data1_s3,		/* data1_s3 */
				alusrc_data2,	/* alusrc_data2 */
				aluctl,			/* ex_aluctl */
				data2_s4,		/* mem_memdata */
				memread_s4,		/* mem_memread */
				memwrite_s4,	/* mem_memwrite */
				wrdata_s5,		/* wb_regdata */
				regwrite_s5		/* wb_regwrite */
			);
	end
end
// }}}

// {{{ flush control
reg flush_s1, flush_s2, flush_s3;
always @(*) begin
	flush_s1 <= 1'b0;
	flush_s2 <= 1'b0;
	flush_s3 <= 1'b0;
	if (pcsrc | jump_s4) begin
		flush_s1 <= 1'b1;
		flush_s2 <= 1'b1;
		flush_s3 <= 1'b1;
	end
end
// }}}

// {{{ stage 1, IF (fetch)

reg  [31:0] pc;
initial begin
	pc <= 32'd0;
end

wire [31:0] pc4;  // PC + 4

always @(*) begin
	flush_s1 <= 1'b0;
	flush_s2 <= 1'b0;
	flush_s3 <= 1'b0;
	if (pcsrc | jump_s4) begin
		flush_s1 <= 1'b1;
		flush_s2 <= 1'b1;
		flush_s3 <= 1'b1;
	end
end
// }}}

// {{{ stage 1, IF (fetch)

always @(posedge clk) begin
	if (stall_s1_s2) 
		pc <= pc;
	else if (pcsrc == 1'b1)
		pc <= baddr_s4;
	else if (jump_s4 == 1'b1)
		pc <= jaddr_s4;
	else
		pc <= pc4;
end

// pass PC + 4 to stage 2

regr #(.N(32)) regr_pc4_s2(.clk(clk),
					.hold(stall_s1_s2), .clear(flush_s1),
					.in(pc4), .out(pc4_s2));

// instruction memory

regr #(.N(32)) regr_im_s2(.clk(clk),
					.hold(stall_s1_s2), .clear(flush_s1),
					.in(inst), .out(inst_s2));

// }}}

// {{{ stage 2, ID (decode)

// decode instruction

regm regm1(.clk(clk), .read1(rs), .read2(rt),
		.data1(data1), .data2(data2),
		.regwrite(regwrite_s5), .wrreg(wrreg_s5),
		.wrdata(wrdata_s5));

// pass rs to stage 3 (for forwarding)

regr #(.N(5)) regr_s2_rs(.clk(clk), .clear(1'b0), .hold(stall_s1_s2),
			.in(rs), .out(rs_s3));

// transfer register data to stage 3

regr #(.N(64)) reg_s2_mem(.clk(clk), .clear(flush_s2), .hold(stall_s1_s2),
			.in({data1, data2}),
			.out({data1_s3, data2_s3}));

// transfer seimm, rt, and rd to stage 3

regr #(.N(10)) reg_s2_rt_rd(.clk(clk), .clear(flush_s2), .hold(stall_s1_s2),
					.in({rt, rd}), .out({rt_s3, rd_s3}));

// transfer PC + 4 to stage 3

regr #(.N(32)) reg_pc4_s2(.clk(clk), .clear(1'b0), .hold(stall_s1_s2),
					.in(pc4_s2), .out(pc4_s3));

// control (opcode -> ...)

control ctl1(.opcode(opcode), .regdst(regdst),
			.branch_eq(branch_eq_s2), .branch_ne(branch_ne_s2),
			.memread(memread),
			.memtoreg(memtoreg), .aluop(aluop),
			.memwrite(memwrite), .alusrc(alusrc),
			.regwrite(regwrite), .jump(jump_s2));

// shift left, seimm
wire [31:0] seimm_sl2;
assign seimm_sl2 = {seimm[29:0], 2'b0};  // shift left 2 bits
// branch address

regr #(.N(2)) branch_s2_s3(.clk(clk), .clear(flush_s2), .hold(1'b0),
			.in({branch_eq_s2, branch_ne_s2}),
			.out({branch_eq_s3, branch_ne_s3}));

regr #(.N(1)) reg_jump_s3(.clk(clk), .clear(flush_s2), .hold(1'b0),
			.in(jump_s2),
			.out(jump_s3));

regr #(.N(32)) reg_jaddr_s3(.clk(clk), .clear(flush_s2), .hold(1'b0),
			.in(jaddr_s2), .out(jaddr_s3));
// }}}

// {{{ stage 3, EX (execute)

// pass through some control signals to stage 4

regr #(.N(4)) reg_s3(.clk(clk), .clear(flush_s2), .hold(1'b0),
			.in({regwrite_s3, memtoreg_s3, memread_s3,
					memwrite_s3}),
			.out({regwrite_s4, memtoreg_s4, memread_s4,
					memwrite_s4}));

// ALU
// second ALU input can come from an immediate value or data

regr #(.N(1)) reg_zero_s3_s4(.clk(clk), .clear(1'b0), .hold(1'b0),
				.in(zero_s3), .out(zero_s4));

// pass ALU result and zero to stage 4

regr #(.N(32)) reg_alurslt(.clk(clk), .clear(flush_s3), .hold(1'b0),
			.in({alurslt}),
			.out({alurslt_s4}));

// pass data2 to stage 4

regr #(.N(32)) reg_data2_s3(.clk(clk), .clear(flush_s3), .hold(1'b0),
			.in(fw_data2_s3), .out(data2_s4));

// write register

regr #(.N(2)) branch_s3_s4(.clk(clk), .clear(flush_s3), .hold(1'b0),
			.in({branch_eq_s3, branch_ne_s3}),
			.out({branch_eq_s4, branch_ne_s4}));

regr #(.N(1)) reg_jump_s4(.clk(clk), .clear(flush_s3), .hold(1'b0),
			.in(jump_s3),
			.out(jump_s4));

regr #(.N(32)) reg_jaddr_s4(.clk(clk), .clear(flush_s3), .hold(1'b0),
			.in(jaddr_s3), .out(jaddr_s4));
// }}}

// {{{ stage 4, MEM (memory)

// pass regwrite and memtoreg to stage 5

regr #(.N(2)) reg_regwrite_s4(.clk(clk), .clear(1'b0), .hold(1'b0),
			.in({regwrite_s4, memtoreg_s4}),
			.out({regwrite_s5, memtoreg_s5}));

// data memory

dm dm1(.clk(clk), .addr(alurslt_s4[8:2]), .rd(memread_s4), .wr(memwrite_s4),
		.wdata(data2_s4), .rdata(rdata));
// pass read data to stage 5

regr #(.N(32)) reg_rdata_s4(.clk(clk), .clear(1'b0), .hold(1'b0),
			.in(rdata),
			.out(rdata_s5));

// pass alurslt to stage 5

regr #(.N(32)) reg_alurslt_s4(.clk(clk), .clear(1'b0), .hold(1'b0),
			.in(alurslt_s4),
			.out(alurslt_s5));

// pass wrreg to stage 5

regr #(.N(5)) reg_wrreg_s4(.clk(clk), .clear(1'b0), .hold(1'b0),
			.in(wrreg_s4),
			.out(wrreg_s5));

// branch

always @(posedge clk) begin
	// default
	block0 <= block0;
	block1 <= block1;
	block2 <= block2;
	block3 <= block3;

	if (index == 2'd0 && rdy)
		block0 <= {1'b1, addr_tag, mem_data};  // { valid, tag, data }

	if (index == 2'd1 && rdy)
		block1 <= {1'b1, addr_tag, mem_data};

	if (index == 2'd2 && rdy)
		block2 <= {1'b1, addr_tag, mem_data};

	if (index == 2'd3 && rdy)
		block3 <= {1'b1, addr_tag, mem_data};
end

always @(*) begin
	case (index)
		0: block = block0;
		1: block = block1;
		2: block = block2;
		//3: block = block3;
		default: block = block3;
	endcase
end

// decode block
wire 			valid;
wire [27:0]		block_tag;
//wire [31:0]		block_data;
//
assign valid		= block[60];
assign block_tag	= block[59:32];
//assign block_data	= block[31:0];
//
//assign data = block_data;
assign data = (rdy == 1'b1) ? mem_data : block[31:0];

// Update block from memory,
// or hold current value.
//
// Anytime the address has been asserted long
// enough for the memory to become ready (rdy)
// the cache will be updated.

always @(posedge clk) begin
	last_addr <= addr;

	next_equals <= equals;
end

// When all the equals bits are set, it is ready

		im1(.clk(clk), .addr(addr), .data(raw_data));

// The address must be held for ND clock cycles
// before it is ready (rdy = 1).
//
// Here this is accomplished with a shift register.
// When address is equal to the previous address
// the lowest bit is set.  When all the bits in
// the shift register are set, the address has
// been held long enough.
//
